policySectionsJson:
[
  { "title": "Information We Collect", "content": "We collect several types of information from and about users of our services, including Personal Identifiers (Name, address, email), Health Information provided voluntarily, and Usage Details (IP addresses, browser types)." },
  { "title": "How We Use Your Information", "content": "We use your information to provide our health services, answer inquiries, send updates about workshops (if you opt in), and improve our website performance." },
  { "title": "Disclosure of Your Information", "content": "We do not sell, rent, or trade your personal information. We may disclose it to affiliates bound by confidentiality or to comply with legal processes." },
  { "title": "Data Security", "content": "We implement measures designed to secure your information from accidental loss and unauthorized access. However, internet transmission is not 100% secure." }
]

